import axios from "axios";

const API_URL = process.env.REACT_APP_API_URL;

export function getOfflineMapping(assessmentId: number) {
  return axios.get(`${API_URL}/assessment-answer/offline-mapping/${assessmentId}`);
}

export function bulkSubmitAnswers(data: {
  assessmentId: number;
  students: {
    userStudentId: number;
    answers: { questionnaireQuestionId: number; optionId: number }[];
  }[];
}) {
  return axios.post(`${API_URL}/assessment-answer/bulk-submit`, data);
}

export function bulkSubmitWithStudents(data: {
  assessmentId: number;
  instituteId: number;
  students: {
    name: string;
    dob?: string;
    phone?: string;
    schoolSectionId?: number;
    answers: { questionnaireQuestionId: number; optionId: number }[];
  }[];
}) {
  return axios.post(`${API_URL}/assessment-answer/bulk-submit-with-students`, data);
}

export function bulkSubmitByRollNumber(data: {
  assessmentId: number;
  instituteId: number;
  students: {
    rollNumber: string;
    answers: { questionnaireQuestionId: number; optionId: number }[];
  }[];
}) {
  return axios.post(`${API_URL}/assessment-answer/bulk-submit-by-rollnumber`, data);
}

// OMR Column Mapping persistence
export function getSavedOmrMapping(assessmentId: number, instituteId: number) {
  return axios.get(`${API_URL}/omr-column-mapping/get/${assessmentId}/${instituteId}`);
}

export function saveOmrMapping(data: {
  assessmentId: number;
  instituteId: number;
  mappingJson: string;
  mappingName?: string;
  questionnaireId?: number;
}) {
  return axios.post(`${API_URL}/omr-column-mapping/save`, data);
}

export function getSavedOmrMappingByQuestionnaire(questionnaireId: number) {
  return axios.get(`${API_URL}/omr-column-mapping/get-by-questionnaire/${questionnaireId}`);
}

export function getAllOmrMappings() {
  return axios.get(`${API_URL}/omr-column-mapping/getAll`);
}
